function evaluation_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('evaluation_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'result' => Request::val('result', ''),
		'select_startup' => Request::lookup('select_startup', ''),
		'recommendation' => Request::val('recommendation', ''),
		'marks' => Request::val('marks', ''),
		'reason_for_not_recommending' => br2nl(Request::val('reason_for_not_recommending', '')),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('evaluation_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		evaluation_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function evaluation_table_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function evaluation_table_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('evaluation_table', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: evaluation_table_before_delete
	if(function_exists('evaluation_table_before_delete')) {
		$args = [];
		if(!evaluation_table_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	// child table: evaluators_table
	$res = sql("SELECT `evaluation_id` FROM `evaluation_table` WHERE `evaluation_id`='{$selected_id}'", $eo);
	$evaluation_id = db_fetch_row($res);
	$rires = sql("SELECT COUNT(1) FROM `evaluators_table` WHERE `evaluation_lookup`='" . makeSafe($evaluation_id[0]) . "'", $eo);
	$rirow = db_fetch_row($rires);
	$childrenATag = '<a class="alert-link" href="evaluators_table_view.php?filterer_evaluation_lookup=' . urlencode($evaluation_id[0]) . '">%s</a>';
	if($rirow[0] && !$AllowDeleteOfParents && !$skipChecks) {
		$RetMsg = $Translation["couldn't delete"];
		$RetMsg = str_replace('<RelatedRecords>', sprintf($childrenATag, $rirow[0]), $RetMsg);
		$RetMsg = str_replace(['[<TableName>]', '<TableName>'], sprintf($childrenATag, 'evaluators_table'), $RetMsg);
		return $RetMsg;
	} elseif($rirow[0] && $AllowDeleteOfParents && !$skipChecks) {
		$RetMsg = $Translation['confirm delete'];
		$RetMsg = str_replace('<RelatedRecords>', sprintf($childrenATag, $rirow[0]), $RetMsg);
		$RetMsg = str_replace(['[<TableName>]', '<TableName>'], sprintf($childrenATag, 'evaluators_table'), $RetMsg);
		$RetMsg = str_replace('<Delete>', '<input type="button" class="btn btn-danger" value="' . html_attr($Translation['yes']) . '" onClick="window.location = `evaluation_table_view.php?SelectedID=' . urlencode($selected_id) . '&delete_x=1&confirmed=1&csrf_token=' . urlencode(csrf_token(false, true)) . (Request::val('Embedded') ? '&Embedded=1' : '') . '`;">', $RetMsg);
		$RetMsg = str_replace('<Cancel>', '<input type="button" class="btn btn-success" value="' . html_attr($Translation[ 'no']) . '" onClick="window.location = `evaluation_table_view.php?SelectedID=' . urlencode($selected_id) . (Request::val('Embedded') ? '&Embedded=1' : '') . '`;">', $RetMsg);
		return $RetMsg;
	}

	sql("DELETE FROM `evaluation_table` WHERE `evaluation_id`='{$selected_id}'", $eo);

	// hook: evaluation_table_after_delete
	if(function_exists('evaluation_table_after_delete')) {
		$args = [];
		evaluation_table_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='evaluation_table' AND `pkValue`='{$selected_id}'", $eo);
}

function evaluation_table_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('evaluation_table', $selected_id, 'edit')) return false;

	$data = [
		'result' => Request::val('result', ''),
		'select_startup' => Request::lookup('select_startup', ''),
		'recommendation' => Request::val('recommendation', ''),
		'marks' => Request::val('marks', ''),
		'reason_for_not_recommending' => br2nl(Request::val('reason_for_not_recommending', '')),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('evaluation_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: evaluation_table_before_update
	if(function_exists('evaluation_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!evaluation_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'evaluation_table',
		backtick_keys_once($set),
		['`evaluation_id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="evaluation_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('evaluation_table', $data['selectedID'], calculated_fields()['evaluation_table']);

	// hook: evaluation_table_after_update
	if(function_exists('evaluation_table_after_update')) {
		if($row = getRecord('evaluation_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['evaluation_id'];
		$args = ['old_data' => $old_data];
		if(!evaluation_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('evaluation_table', $selected_id);
}

